let SuperSimpleStorage = require('supersimplestorage');


export interface StorageOptions {
  storageFolder: string;
  dotsToFolders: boolean;
  fileExtension: string;
}


const DEFAULT_OPTIONS = {
  storageFolder: 'tmp_storage_folder',
  dotsToFolders: true,
  fileExtension: 'txt'
};



export class Node {

  constructor(public key: string, public data: any, private _storage) {

  }

  save() {
    return new Promise( (res, rej) => {
      this._storage.save(this.key, this.data,
        (content) => res(),
        (error) => rej(error));
    });
  }
}


export class _Persistence {

  private _storage: any;
  private _map = new Map<string, Node>();

  constructor(options?: StorageOptions) {

    let selectedOptions = options || DEFAULT_OPTIONS;

    this._storage = new SuperSimpleStorage(selectedOptions);
  }

  get(key: string): Promise<Node> {
    let node = this._map.get(key);
    if (node) {
      return Promise.resolve(node);
    }
    else {
      return new Promise((res, rej) => {
        this._storage.open(key,
          (content) => {
            res(this._createNode(key, content));
          },
          (error) => {
            if (error.toString() === 'Storage item not found.') {
              res(this._createNode(key, {}));
            }
            else {
              rej(error);
            }
          });
      });
    }
  }

  private _createNode(key, data) {
    let node = new Node(key, data, this._storage);
    this._map.set(key, node);
    return node;
  }

}


let persistence: _Persistence;



export default class Persistence {

  constructor() {
    throw new Error(`This class shouldn't be instantiated, use 'getInstance'`);
  }

  static getInstance(options?: StorageOptions): _Persistence {
    if (!persistence) {
      persistence = new _Persistence(options);
    }

    return persistence;
  }

  /**
   * Should only be called for testing purposes
   * @param options
   * @returns {_Persistence}
   * @private
   */
  static _resetInstance(options?: StorageOptions): _Persistence {
    persistence = new _Persistence(options);

    return persistence;
  }
}